import{_ as t,o,c as a,a2 as n}from"./chunks/framework.BYlK8ftn.js";const g=JSON.parse('{"title":"World map & zones","description":"","frontmatter":{},"headers":[],"relativePath":"guide/world-map.md","filePath":"guide/world-map.md","lastUpdated":1781996558000}'),r={name:"guide/world-map.md"};function s(d,e,i,l,c,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="world-map-zones" tabindex="-1">World map &amp; zones <a class="header-anchor" href="#world-map-zones" aria-label="Permalink to &quot;World map &amp; zones&quot;">​</a></h1><p>The world is split into <strong>four zones</strong> (game-plan §0). The world-map overlay lets the player <strong>fast-travel</strong> between the zones that have a playable scene. This is the Phase-3 scaffolding (E3.1); zone-streaming on border crossing is E3.2, and the caravan/loot loop is E3.3/E3.4.</p><p>For the level-design lore and layout targets behind each zone, see the <a href="./world-specs">World specs</a>.</p><h2 id="the-four-zones" tabindex="-1">The four zones <a class="header-anchor" href="#the-four-zones" aria-label="Permalink to &quot;The four zones&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Id</th><th>Display name</th><th>Lore name</th><th>Owner</th><th>Status</th></tr></thead><tbody><tr><td><code>human-lands</code></td><td>Human lands</td><td>The Salt Road of Velya</td><td>Neutral</td><td>available</td></tr><tr><td><code>empire</code></td><td>Empire</td><td>The Imperial March</td><td>The Emperor</td><td>locked</td></tr><tr><td><code>forest</code></td><td>Forest</td><td>The Emerald Thicket of Lysaen</td><td>Forest Elves</td><td>available</td></tr><tr><td><code>mountains</code></td><td>Mountains</td><td>Black Crown Pass</td><td>The Villain</td><td>locked</td></tr></tbody></table><p><code>available</code> zones have a scene and can be travelled to. <code>locked</code> zones are declared in the registry so the world map can list all four, but travel to them is disabled until their scene is built. The open zones are <strong>Forest</strong> and <strong>Human Lands</strong>; MPG.5 populates both on entry with caravans and soldier patrols so fast-travel never lands the player in an empty combat zone.</p><h2 id="zone-registry" tabindex="-1">Zone registry <a class="header-anchor" href="#zone-registry" aria-label="Permalink to &quot;Zone registry&quot;">​</a></h2><p>The registry lives in <code>src/game/world/</code> (engine-agnostic — no Babylon or React):</p><ul><li><code>zones.ts</code> — the four <code>ZoneDefinition</code>s (<code>id</code>, <code>displayName</code>, <code>loreName</code>, <code>ownerFaction</code>/<code>ownerLabel</code>, <code>spawn</code> transform, <code>status</code>, and a <code>streaming</code> entry point referencing the zone&#39;s asset manifest + scene key).</li><li><code>index.ts</code> — lookups (<code>listZones</code>, <code>getZone</code>, <code>isZoneAvailable</code>) and the pure fast-travel resolver <code>planTravel(currentZoneId, targetZoneId)</code>, which validates the target (must exist, be unlocked, and not be the current zone) and returns the destination zone plus the spawn to teleport to.</li></ul><p>Zone ids are persisted in saves via <code>playerSlice.zoneId</code>, so they are <strong>forever</strong> — never rename one without a save migration.</p><h2 id="fast-travel-flow" tabindex="-1">Fast-travel flow <a class="header-anchor" href="#fast-travel-flow" aria-label="Permalink to &quot;Fast-travel flow&quot;">​</a></h2><ol><li>The player opens the world map from the HUD <strong>Travel</strong> button or by pressing <strong>M</strong> during live play.</li><li>Selecting an available zone shows a <strong>Travel / Cancel</strong> confirm (a two-step affordance so a stray click never teleports the player).</li><li>On confirm, <code>App</code> calls <code>planTravel</code>, stages the destination spawn on the <code>playerRuntime</code> bridge (<code>stageSpawn</code>), and dispatches <code>setZone(targetId)</code>.</li><li>Changing <code>zoneId</code> remounts <code>GameCanvas</code> with the destination scene (<code>createZoneScene</code> in <code>src/scenes/zoneScenes.ts</code>), which consumes the staged spawn on boot (<code>takeSpawn</code>) — landing the player at the zone&#39;s spawn point.</li></ol><p>The overlay handles its <strong>empty</strong>, <strong>loading</strong> (&quot;Travelling…&quot;), and <strong>error</strong> states. It is built against the E3.1-UX requirements; visual polish tracks Iris&#39;s wireframes.</p><h2 id="streaming-entry-point-e3-2-wired-in-flo-345" tabindex="-1">Streaming entry point (E3.2, wired in FLO-345) <a class="header-anchor" href="#streaming-entry-point-e3-2-wired-in-flo-345" aria-label="Permalink to &quot;Streaming entry point (E3.2, wired in FLO-345)&quot;">​</a></h2><p><code>createZoneScene(zoneId, canvas, options)</code> is the single place a zone&#39;s scene is booted. Each zone scene drives a <code>ZoneStreamingManager</code> and enters its <code>ZoneManifest</code> (<code>getZoneManifest(zoneId)</code>) on boot, so the zone&#39;s content streams in on arrival and disposes when the scene is torn down on the next border crossing. See <a href="./asset-streaming">Asset streaming → Wired into travel</a> for the manager lifecycle and the per-zone manifests in <code>src/game/streaming/zoneManifests.ts</code>.</p>',15)])])}const m=t(r,[["render",s]]);export{g as __pageData,m as default};
